from agent import *from models.products import *import reDUPE_PRODS = set()def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def run(context, session):    session.browser.use_new_parser = True    session.queue(Request('https://www.everki.com/us_en/'), process_frontpage, {})def process_frontpage(data, context, session):    strip_namespace(data)    cats = data.xpath('//nav/ul/li[contains(@class, "level-0")]')    for cat in cats:        name = cat.xpath('a/span[not(@class)]/text()').string()        cats1 = cat.xpath('//nav/ul/li[contains(@class, "level-0")]/div//ul/li[contains(@class, "level-1")][span[contains(., "Screen Size") or contains(., "by Category")]]/ul/li/a[not(contains(., "View All"))]')        for cat1 in cats1:            name1 = cat1.xpath('text()').string()            url = cat1.xpath('@href').string()            if name1 and url:                url += '?product_list_limit=30'                session.queue(Request(url), process_prodlist, dict(cat=name+'|'+name1))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//ul/li//div[contains(@class, "product-info")]')    for prod in prods:        name = prod.xpath('div/a[@class="product-item-link"]/text()').string()        url = prod.xpath('div/a[@class="product-item-link"]/@href').string()        revs_cnt = prod.xpath('.//div[contains(@class, "rating")]/following-sibling::div/span/text()').string()        if revs_cnt and int(revs_cnt.strip('()')) > 0:            session.queue(Request(url+'?limit=50'), process_product, dict(context, name=name, url=url))    next_url = data.xpath('//nav//a[contains(@class, "next")]/@href').string()    if next_url:        session.queue(Request(next_url), process_prodlist, dict())def process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.url = context['url']    product.category = context['cat']    product.manufacturer = 'Everki'    product.ssid = data.xpath('//div[@class="product-info-main"]//@id[contains(., "product-price")]').string().split('price-')[-1]    product.sku = data.xpath('//div[@id="product-details"]//span[@x-html="skuValue"]/text()').string()    if product.sku:        product.add_property(type='id.manufacturer', value=product.sku)    ean = data.xpath('//meta[@class="upc_code" or contains(@itemprop, "gtin")]/@content').string()    if ean and ean.isdigit() and len(ean) > 10:        product.add_property(type='id.ean', value=ean)    if product.ssid not in DUPE_PRODS:        context['product'] = product        process_reviews(data, context, session)        DUPE_PRODS.add(product.ssid)def process_reviews(data, context, session):    strip_namespace(data)    product = context['product']    revs = data.xpath('//div[@itemprop="review"]')    for rev in revs:        review = Review()        title = rev.xpath('div[@itemprop="name"]//text()[normalize-space()]').string()        if title:            review.title = remove_emoji(title).strip('*+=-_\n ')        review.type = 'user'        review.url = product.url        review.date = rev.xpath('.//time/@datetime').string()        author = rev.xpath('.//strong[@itemprop="author"]/span/text()').string()        if author:            author = remove_emoji(author).strip('*+=-_\n ')            if author:                review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.xpath('.//span[@itemprop="ratingValue"]/text()').string()        if grade_overall:            grade_overall = float(grade_overall)            review.grades.append(Grade(type='overall', value=grade_overall, best=5.0))        excerpt = rev.xpath('div[@itemprop="description"]//text()[not(parent::button or parent::span[contains(@id, "ellipsis")])][normalize-space()]').string(multiple=True)        if excerpt:            excerpt = remove_emoji(excerpt).strip('*+=-_\n ')            if excerpt:                review.add_property(type='excerpt', value=excerpt)                review.ssid = review.digest() if author else review.digest(excerpt)                product.reviews.append(review)    next_url = data.xpath('//li[contains(@class, "item-next")]//a/@href').string()    if next_url:        session.do(Request(next_url), process_reviews, dict(product=product))    elif product.reviews:        session.emit(product)